import_script:
import { createClient, SupabaseClient } from '@supabase/supabase-js';

import laoureuxIViolino from './laoureux-i-violino.json';
import laoureuxIIIViolino from './laoureux-iii-violino.json';
import metodoFacilitadoViola from './metodo-facilitado-viola.json';
import dotzauerIVioloncello from './dotzauer-i-violoncello.json';
import dotzauerIIVioloncello from './dotzauer-ii-violoncello.json';
import almeidaDiasEufonio from './almeida-dias-eufonio.json';
import almeidaDiasTrombone from './almeida-dias-trombone.json';
import almeidaDiasTuba from './almeida-dias-tuba.json';
import giampieriIClarinete from './giampieri-i-clarinete.json';
import giampieriIIClarinete from './giampieri-ii-clarinete.json';
import naborClarinete from './nabok-pires-camargo-clarinete.json';
import rubankClarinete from './rubank-basico-clarinete.json';
import giampieriIClarone from './giampieri-i-clarone.json';
import giampieriIIClarone from './giampieri-ii-clarone.json';
import naborClarone from './nabok-pires-camargo-clarone.json';
import rubankClarone from './rubank-basico-clarone.json';
import amadeusRussoSaxSoprano from './amadeus-russo-sax-soprano.json';
import amadeusRussoSaxAlto from './amadeus-russo-sax-alto.json';
import amadeusRussoSaxTenor from './amadeus-russo-sax-tenor.json';

export const METHOD_CATALOG = [
  laoureuxIViolino,
  laoureuxIIIViolino,
  metodoFacilitadoViola,
  dotzauerIVioloncello,
  dotzauerIIVioloncello,
  almeidaDiasEufonio,
  almeidaDiasTrombone,
  almeidaDiasTuba,
  giampieriIClarinete,
  giampieriIIClarinete,
  naborClarinete,
  rubankClarinete,
  giampieriIClarone,
  giampieriIIClarone,
  naborClarone,
  rubankClarone,
  amadeusRussoSaxSoprano,
  amadeusRussoSaxAlto,
  amadeusRussoSaxTenor,
] as const;

export const FALLBACK_METHOD = {
  method: { id: 'custom', name: 'Método personalizado' },
  structure: [{ lesson: 1, pageitems: [], lessonitems: [] }],
} as const;

export const FAMILY_BY_INSTRUMENT: Record<string, string> = {
  violino: 'cordas-arco',
  viola: 'cordas-arco',
  violoncelo: 'cordas-arco',
  eufonio: 'metais-boca',
  trombone: 'metais-boca',
  tuba: 'metais-boca',
  clarinete: 'madeira-palheta-simples',
  clarone: 'madeira-palheta-simples',
  'sax-soprano': 'madeira-palheta-simples',
  'sax-alto': 'madeira-palheta-simples',
  'sax-tenor': 'madeira-palheta-simples',
};

export const METHODS_BY_INSTRUMENT: Record<string, typeof METHOD_CATALOG[number][]> =
  METHOD_CATALOG.reduce((acc, item) => {
    for (const instrument of item.method.instruments) {
      acc[instrument] ??= [];
      acc[instrument].push(item);
    }
    return acc;
  }, {} as Record<string, typeof METHOD_CATALOG[number][]>);

export function listMethods(instrument?: string) {
  if (!instrument) return METHOD_CATALOG.map((item) => item.method);
  return (METHODS_BY_INSTRUMENT[instrument] ?? []).map((item) => item.method);
}

export function getMethodCatalog(methodId: string) {
  return METHOD_CATALOG.find((item) => item.method.id === methodId) ?? null;
}

export function validateMethodForInstrument(methodId: string, instrument: string) {
  const method = getMethodCatalog(methodId);
  if (!method) return false;
  return method.method.instruments.includes(instrument);
}

export function saveMethodGuard(methodId: string, instrument: string) {
  if (!validateMethodForInstrument(methodId, instrument)) {
    throw new Error(`Método ${methodId} não é permitido para o instrumento ${instrument}`);
  }
  return true;
}

export function deriveFamilyByInstrument(instrument: string) {
  return FAMILY_BY_INSTRUMENT[instrument] ?? null;
}

export function getCatalogOrFallback(instrument: string, methodId?: string) {
  if (!methodId) return FALLBACK_METHOD;
  const method = getMethodCatalog(methodId);
  if (!method) return FALLBACK_METHOD;
  if (!method.method.instruments.includes(instrument)) return FALLBACK_METHOD;
  return method;
}

export function getBulkEntrySuggestions(instrument: string) {
  return (METHODS_BY_INSTRUMENT[instrument] ?? []).flatMap((item) =>
    item.structure.flatMap((row) => [
      ...row.lessonitems,
      ...row.exercises,
      ...row.contentitems.map((content) =>
        typeof content.number === 'number'
          ? `${content.type} ${content.number}`
          : `${content.type} ${content.number}`.trim()
      ),
    ])
  );
}

export type ImportOptions = {
  methodsTable?: string;
  structureTable?: string;
  upsertOn?: 'id';
};

export function assertCatalogIntegrity() {
  const ids = new Set<string>();
  for (const item of METHOD_CATALOG) {
    if (!item.method.instruments?.length) {
      throw new Error(`Método sem instruments: ${item.method.id}`);
    }
    if (ids.has(item.method.id)) {
      throw new Error(`ID duplicado: ${item.method.id}`);
    }
    ids.add(item.method.id);

    const last = item.structure[item.structure.length - 1];
    if (!last || last.page_end !== item.method.total_pages) {
      throw new Error(`total_pages inválido em ${item.method.id}`);
    }

    for (const row of item.structure) {
      const expected = Array.from(
        { length: row.page_end - row.page_start + 1 },
        (_, index) => row.page_start + index
      );
      if (JSON.stringify(expected) !== JSON.stringify(row.pageitems)) {
        throw new Error(`pageitems inválido em ${item.method.id} / lesson ${row.lesson}`);
      }
    }
  }
  return true;
}

export async function importCatalog(
  supabase: SupabaseClient,
  options: ImportOptions = {}
) {
  assertCatalogIntegrity();

  const methodsTable = options.methodsTable ?? 'methods_catalog';
  const structureTable = options.structureTable ?? 'method_structure';

  const methodRows = METHOD_CATALOG.map((item) => item.method);
  const { error: methodsError } = await supabase
    .from(methodsTable)
    .upsert(methodRows, { onConflict: options.upsertOn ?? 'id' });

  if (methodsError) throw methodsError;

  const structureRows = METHOD_CATALOG.flatMap((item) =>
    item.structure.map((row) => ({
      method_id: item.method.id,
      ...row,
    }))
  );

  const { error: structureError } = await supabase
    .from(structureTable)
    .upsert(structureRows, { onConflict: 'method_id,lesson' });

  if (structureError) throw structureError;

  return {
    imported_methods: methodRows.length,
    imported_structure_rows: structureRows.length,
  };
}

